diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index b821da03c16e..446780103b37 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -2969,8 +2969,56 @@ void InnerLoopVectorizer::fixVectorizedLoop(VPTransformState &State,

   // Fix live-out phis not already fixed earlier.
   for (const auto &KV : Plan.getLiveOuts())
+  // Verify and fix PHI nodes in exit blocks to ensure they have correct number of entries
+  for (BasicBlock *Exit : ExitBlocks) {
+    unsigned NumPreds = std::distance(pred_begin(Exit), pred_end(Exit));
+    for (PHINode &PN : Exit->phis()) {
+      if (PN.getNumOperands() != NumPreds) {
+        // Save the original value (should be the same for all predecessors)
+        Value *OriginalVal = PN.getIncomingValue(0);
+        BasicBlock *OriginalPred = PN.getIncomingBlock(0);
+        PN.removeAllOperands();
+        for (BasicBlock *Pred : predecessors(Exit)) {
+          PN.addIncoming(OriginalVal, Pred);
+        }
+      }
+    }
+  }
     KV.second->fixPhi(Plan, State);

+  // Ensure all PHI nodes in exit blocks have correct number of entries
+  for (BasicBlock *Exit : ExitBlocks) {
+    SmallVector<BasicBlock *> Preds;
+    for (auto *Pred : predecessors(Exit))
+      Preds.push_back(Pred);
+    for (PHINode &PN : Exit->phis()) {
+      if (PN.getNumOperands() != Preds.size()) {
+        // Find the original incoming value from the loop
+        Value *OriginalValue = nullptr;
+        BasicBlock *OriginalPred = nullptr;
+        for (unsigned i = 0; i < PN.getNumOperands(); ++i) {
+          if (std::find(Preds.begin(), Preds.end(), PN.getIncomingBlock(i)) != Preds.end()) {
+            OriginalValue = PN.getIncomingValue(i);
+            OriginalPred = PN.getIncomingBlock(i);
+            break;
+          }
+        }
+        if (!OriginalValue) {
+          // This shouldn't happen, but if it does, use undef
+          OriginalValue = UndefValue::get(PN.getType());
+          OriginalPred = Preds[0];
+        }
+        // Clear and rebuild PHI node
+        PN.removeAllOperands();
+        for (BasicBlock *Pred : Preds) {
+          if (Pred == OriginalPred)
+            PN.addIncoming(OriginalValue, Pred);
+          else
+            PN.addIncoming(OriginalValue, Pred);
+        }
+      }
+    }
+  }
   for (Instruction *PI : PredicatedInstructions)
     sinkScalarOperands(&*PI);

